+                str_tok.lexeme[1 .. str_tok.lexeme.len - 1]
+            else
+                str_tok.lexeme;
+            try parts_list.append(self.allocator, .{ .literal = content });
+        } else if (next_type == .FString) {
+            // Concatenate another f-string's parts
